import javax.xml.xpath.XPathFactory;
import java.io.StringReader;

public class ReportService {

    /**
     * Extracts a metric value from XML content using an XPath expression.
     *
     * @param xmlContent      The XML content as a string.
     * @param xpathExpression The XPath expression to evaluate.
     * @return The extracted metric value as a string, or null if not found.
     * @throws IllegalArgumentException if input parameters are invalid or processing fails.
     */
    public String extractMetric(String xmlContent, String xpathExpression) {
        // Validate input parameters
        if (xmlContent == null || xmlContent.trim().isEmpty()) {
            throw new IllegalArgumentException("XML content cannot be null or empty");
        }
        if (xpathExpression == null || xpathExpression.trim().isEmpty()) {
            throw new IllegalArgumentException("XPath expression cannot be null or empty");
        }

        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        XPathFactory xPathFactory = XPathFactory.newInstance();

        try {
            // Secure XML parsing: disable external entities and DTDs to prevent XXE attacks
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new InputSource(new StringReader(xmlContent)));

            XPath xpath = xPathFactory.newXPath();
            XPathExpression compiledExpression = xpath.compile(xpathExpression);

            // Evaluate XPath expression
            Object result = compiledExpression.evaluate(document, XPathConstants.NODE);

            if (result instanceof Node) {
                Node node = (Node) result;
                return node.getTextContent();
            } else {
                // If the XPath returns a non-node result (e.g., string/number), convert to string
                return compiledExpression.evaluate(document);
            }

        } catch (javax.xml.parsers.ParserConfigurationException e) {
            throw new IllegalArgumentException("XML parser configuration error: " + e.getMessage(), e);
        } catch (org.xml.sax.SAXException e) {
            throw new IllegalArgumentException("Invalid XML content: " + e.getMessage(), e);
        } catch (java.io.IOException e) {
            throw new IllegalArgumentException("XML reading error: " + e.getMessage(), e);
        } catch (javax.xml.xpath.XPathExpressionException e) {
            throw new IllegalArgumentException("Invalid XPath expression: " + e.getMessage(), e);
        } catch (Exception e) {
            throw new IllegalArgumentException("Unexpected error during XML processing: " + e.getMessage(), e);
        }
    }
}
